Scripts.OnShow:
if (Dcr_Saved.CureWyvernSting) then
    this:SetChecked(1);
    DCR_SKIP_LIST["Wyvern Sting"] = false
else
    this:SetChecked(0);
end
if (DCR_CAN_CURE_POISON or Dcr_Saved.LeaderMode) then
    this:Enable();
else
    this:SetChecked(0);
    this:Disable();
end

Scripts.OnMouseUp:
if ( this.isMoving ) then
this:StopMovingOrSizing();
-- DecursiveAfflictedListFrame:StopMovingOrSizing();
this.isMoving = false;
end

Scripts.OnMouseDown:
if ( ( ( not this.isLocked ) or ( this.isLocked == 0 ) ) and ( arg1 == "LeftButton" ) ) then
this:StartMoving();
-- DecursiveAfflictedListFrame:StartMoving();
this.isMoving = true;
end
if (arg1 == "RightButton") then
Dcr_ShowHideButtons();
end

Scripts.OnHide:
if ( this.isMoving ) then
this:StopMovingOrSizing();
-- DecursiveAfflictedListFrame:StopMovingOrSizing();
this.isMoving = false;
end

