Scripts.OnClick:
-- 修改：允许在非团长模式下也能选择魔法
if Dcr_Saved.LeaderMode then
	Dcr_Saved.CureMagic = (this:GetChecked() == 1);
else
	Dcr_Saved.CureMagic = (this:GetChecked() == 1);
end
Dcr_On_CureOrderCheckBox_Update(this);

Scripts.OnLoad:
Dcr_ThisSetText(DCR_LOC_AF_TYPE [DCR_MAGIC]);
this.CureFunction = Dcr_Cure_Magic;
this.CureType = DCR_MAGIC;
this.CurePos = 0;
Dcr_CureTypeCheckBoxes[DCR_MAGIC] = this;

Scripts.OnShow:
if (Dcr_Saved.CureMagic) then
this:SetChecked(1);
else
this:SetChecked(0);
end
if (DCR_CAN_CURE_MAGIC or DCR_CAN_CURE_ENEMY_MAGIC or Dcr_Saved.LeaderMode) then
this:Enable();
this:SetAlpha(1); -- 直接设置不透明
else
this:SetChecked(0);
this:Disable();
this:SetAlpha(0.5); -- 直接设置半透明
end
Dcr_On_CureOrderCheckBox_Update(this);

