Scripts.OnClick:
Dcr_Saved.LeaderMode = (this:GetChecked() == 1);
-- 更新其他复选框状态
-- 修改：启用团长模式时不自动勾选任何监控选项

-- 禁用团长模式时重置监控选项
local checkBoxes = {DcrOptionsFrame2LeaderMonitorMagic, DcrOptionsFrame2LeaderMonitorPoison, DcrOptionsFrame2LeaderMonitorDisease, DcrOptionsFrame2LeaderMonitorCurse};
for i=1, table.getn(checkBoxes) do
    local cb = checkBoxes[i];
    if cb then
        cb:SetChecked(Dcr_Saved.LeaderMode and cb:GetChecked());
    end
end

-- 更新监控选项的交互状态
local enabled = Dcr_Saved.LeaderMode;
DcrOptionsFrame2LeaderMonitorMagic:EnableMouse(enabled);
DcrOptionsFrame2LeaderMonitorMagic:SetAlpha(enabled and 1 or 0.5);
DcrOptionsFrame2LeaderMonitorDisease:EnableMouse(enabled);
DcrOptionsFrame2LeaderMonitorDisease:SetAlpha(enabled and 1 or 0.5);
DcrOptionsFrame2LeaderMonitorPoison:EnableMouse(enabled);
DcrOptionsFrame2LeaderMonitorPoison:SetAlpha(enabled and 1 or 0.5);
DcrOptionsFrame2LeaderMonitorCurse:EnableMouse(enabled);
DcrOptionsFrame2LeaderMonitorCurse:SetAlpha(enabled and 1 or 0.5);

Scripts.OnShow:
this:SetChecked(Dcr_Saved.LeaderMode or false);

-- 更新监控选项的交互状态
local enabled = Dcr_Saved.LeaderMode;
DcrOptionsFrame2LeaderMonitorMagic:EnableMouse(enabled);
DcrOptionsFrame2LeaderMonitorMagic:SetAlpha(enabled and 1 or 0.5);
DcrOptionsFrame2LeaderMonitorDisease:EnableMouse(enabled);
DcrOptionsFrame2LeaderMonitorDisease:SetAlpha(enabled and 1 or 0.5);
DcrOptionsFrame2LeaderMonitorPoison:EnableMouse(enabled);
DcrOptionsFrame2LeaderMonitorPoison:SetAlpha(enabled and 1 or 0.5);
DcrOptionsFrame2LeaderMonitorCurse:EnableMouse(enabled);
DcrOptionsFrame2LeaderMonitorCurse:SetAlpha(enabled and 1 or 0.5);

-- 检查UnitXP插件是否存在
local hasUnitXP = false;
if type(UnitXP) == "function" then
    -- 尝试调用UnitXP来确认它是可用的
    local status = pcall(UnitXP, "nop", "nop");
    hasUnitXP = status;
end

if (DCR_CLASS_SHAMAN == Dcr_PlayerClass) and hasUnitXP then
    this:SetChecked(Dcr_Saved.ShamanTotemPriority or false);
    this:Enable();
    this:SetAlpha(1); -- 启用时不透明
else
    this:SetChecked(0);
    this:Disable();
    this:SetAlpha(0.5); -- 禁用时半透明
end

getglobal(this:GetName().."High"):SetText("2.0");
getglobal(this:GetName().."Low"):SetText("0.5");
getglobal(this:GetName().."Text"):SetText("UI比例: " .. tostring(Dcr_Saved.UIScale or 1.0));
this:SetValue(Dcr_Saved.UIScale or 1.0);

Scripts.OnValueChanged:
Dcr_Saved.UIScale = this:GetValue();
getglobal(this:GetName().."Text"):SetText("UI比例: " .. string.format("%.1f", Dcr_Saved.UIScale));
Dcr_UpdateUIScale();
